INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-57f41407-moex-00302', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '甲主張乙詐領其存款新臺幣200萬元，至臺灣臺北地方法院起訴請求乙如數返還，分由該法院民事庭 A法官獨任審理，於審理期間，因甲年老不善陳述，偕同其子丙為輔佐人到庭。關於法官迴避，下列 敘述何者正確？', '["如A於分案後4個月均未實質進行本件訴訟，即屬未勤勉、妥速執行職務而有偏頗之虞，甲及乙均得 聲請A迴避", "如A執行職務有偏頗之虞，丙雖為輔佐人，亦得於言詞辯論時，經在場之甲同意，聲請法官迴避", "如乙以A未准許其證據調查聲請為由聲請法官迴避時，為免臺灣臺北地方法院陷於利害衝突、難以 公平審理，得向直接上級法院即臺灣高等法院聲請", "如甲於收受本件訴訟終局判決時，始發現乙曾為A在大學兼任教職時之學生，甲即得認為A執行職 務有偏頗之虞而聲請法官迴避"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00303', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '下列何種情形，被告無當事人能力？', '["A對在我國營業之外國公司B起訴", "A對B公司之分公司就其業務範圍內之事項起訴", "A對設有代表人之非法人團體B起訴", "A於民國108年9月1日對B起訴，而B已於同年6月30日死亡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00304', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', 'A對B起訴，C主張就A、B之訴訟有法律上利害關係，為輔助A。下列訴訟行為，何者C不得為之？', '["第一審法院判決A敗訴，C得於聲請參加訴訟之同時，就第一審判決提起上訴", "第一審法院判決A敗訴確定，C得於聲請參加訴訟之同時，就第一審判決提起再審之訴", "於第二審程序聲請參加訴訟之同時，為時效抗辯", "第一審法院裁定命A補繳上訴費，C得於聲請參加訴訟之同時，就關於核定訴訟標的價額部分提起抗告"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00305', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '甲、乙、丙公同共有之A地被丁無權占用，甲、乙、丙欲對丁請求占用A地之不當得利，然而對於是否 以訴訟方式請求，未達成共識。依據實務見解，下列敘述何者正確？', '["若甲、乙為原告，對丁提起訴訟，應得丙之同意", "甲、乙得不顧丙之意願，共同為原告，對丁提起訴訟", "甲、乙、丙必須共同起訴，方具有當事人適格", "若甲、乙為原告，對丁提起訴訟，法院得依職權裁定命丙於一定期間內追加為原告。逾期未追加者， 視為已一同起訴"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00306', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '下列何者，徵收裁判費新臺幣3,000元？', '["非因財產權而起訴", "抗告", "聲請支付命令", "起訴前聲請保全證據"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00307', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於應受送達人，下列敘述何者正確？', '["原告甲為7歲之人，對甲為送達者，應向其全體法定代理人為之", "原告甲為在軍隊服役之軍人，對於甲為送達者，應囑託國防部為之", "原告甲為在中華民國有營業所之外國法人，對於甲為送達者，應向其在外國之法人為之", "原告甲為在監所之受刑人，對於甲為送達者，應囑託法務部為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00308', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於期日，下列敘述何者正確？', '["涉及就學中之未成年人為關係人之事件，司法事務官應依職權通知當事人，以週末或週日為指定之期日", "書記官核定期日後，應報請審判長許可，並由書記官指揮執達員製作期日通知書送達各訴訟關係人", "期日，以朗讀案由為始", "如因受命法官或受託法官職務異動，致需變更或延展期日，應由書記官製作處分書通知當事人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00309', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於裁判，下列敘述何者正確？', '["判決，應本於當事人及其委任之訴訟代理人共同進行之言詞辯論為之。一般財產權事件之訴訟標的 金額達新臺幣150萬元以上者，至少應行2次言詞辯論程序，始得為判決", "未參與為判決基礎辯論之陪席法官，應以書面添具其得心證理由後，始得參與判決", "通常訴訟事件之判決，原則上應記載得心證之理由", "原告之訴，依其所訴事實，在法律上顯無理由者，法院得於準備程序終結後，逕以裁定駁回之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00310', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '關於除權判決，下列敘述何者錯誤？', '["不得上訴", "對於除權判決所附之限制，得為抗告", "對於除權判決所附之保留，得為抗告", "對於除權判決不得提起撤銷訴訟"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL),
  ('aboriginal-57f41407-moex-00311', 'aboriginal-57f41407', 'aboriginal-57f41407-moex-112-1611a566', 'sub-aboriginal-57f41407-03', NULL, 'single_choice', '甲對乙提起清償借款之訴，於第一審本案終局判決後，撤回起訴。1年後，甲又向管轄法院對乙提起 同一之清償借款之訴，受訴法院應如何裁判？', '["以欠缺權利保護必要判決駁回", "經言詞辯論後為本案判決", "以裁定駁回起訴", "以無理由判決駁回起訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:16+00:00", "source_pdf_sha1": "e10bee6f4246", "answer_pdf_sha1": "eb33bd1ad3bd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0812", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "錄事"}'::jsonb, NULL)
